// === MTF ANALYZER ===
// Мульти-таймфрейм анализ с RSI, EMA, MACD, ATR
// Score-based система генерации торговых сигналов

const symbol = $('Loop Over Pairs').item.json.symbol;

// Утилиты расчёта индикаторов
function parseCandles(raw) {
  if (!raw || !Array.isArray(raw)) return [];
  return raw.map(c => ({
    ts: parseInt(c[0]),
    o: parseFloat(c[1]),
    h: parseFloat(c[2]),
    l: parseFloat(c[3]),
    c: parseFloat(c[4]),
    v: parseFloat(c[5])
  })).sort((a, b) => a.ts - b.ts);
}

function calcRSI(closes, period = 14) {
  if (closes.length < period + 1) return 50;
  let gains = 0, losses = 0;
  for (let i = closes.length - period; i < closes.length; i++) {
    const diff = closes[i] - closes[i - 1];
    if (diff > 0) gains += diff;
    else losses += Math.abs(diff);
  }
  const avgGain = gains / period;
  const avgLoss = losses / period;
  if (avgLoss === 0) return 100;
  const rs = avgGain / avgLoss;
  return 100 - (100 / (1 + rs));
}

function calcEMA(closes, period) {
  if (closes.length < period) return closes[closes.length - 1];
  const k = 2 / (period + 1);
  let ema = closes.slice(0, period).reduce((a, b) => a + b) / period;
  for (let i = period; i < closes.length; i++) {
    ema = closes[i] * k + ema * (1 - k);
  }
  return ema;
}

function calcMACD(closes) {
  const ema12 = calcEMA(closes, 12);
  const ema26 = calcEMA(closes, 26);
  const macdLine = ema12 - ema26;
  // Сигнальная линия — EMA(9) от MACD (упрощённая)
  const signal = macdLine * 0.8; // Приближение
  const histogram = macdLine - signal;
  return { macdLine, signal, histogram };
}

function calcATR(candles, period = 14) {
  if (candles.length < period + 1) return 0;
  let trSum = 0;
  for (let i = candles.length - period; i < candles.length; i++) {
    const tr = Math.max(
      candles[i].h - candles[i].l,
      Math.abs(candles[i].h - candles[i - 1].c),
      Math.abs(candles[i].l - candles[i - 1].c)
    );
    trSum += tr;
  }
  return trSum / period;
}

// Парсим данные со всех трёх таймфреймов
const items = $input.all();
let raw15m = [], raw1h = [], raw4h = [];

try {
  // Данные приходят в разном формате — обрабатываем оба варианта
  const d0 = items[0]?.json?.data || items[0]?.json || [];
  const d1 = items[1]?.json?.data || items[1]?.json || [];
  const d2 = items[2]?.json?.data || items[2]?.json || [];
  raw15m = Array.isArray(d0) ? d0 : [];
  raw1h = Array.isArray(d1) ? d1 : [];
  raw4h = Array.isArray(d2) ? d2 : [];
} catch(e) {
  return [{ json: { signal: 'HOLD', reason: 'Ошибка парсинга данных: ' + e.message, symbol } }];
}

const candles15m = parseCandles(raw15m);
const candles1h = parseCandles(raw1h);
const candles4h = parseCandles(raw4h);

if (candles15m.length < 20 || candles1h.length < 20 || candles4h.length < 50) {
  return [{ json: { signal: 'HOLD', reason: 'Недостаточно данных для анализа', symbol } }];
}

// Текущая цена
const price = candles15m[candles15m.length - 1].c;

// RSI для каждого таймфрейма
const closes15m = candles15m.map(c => c.c);
const closes1h = candles1h.map(c => c.c);
const closes4h = candles4h.map(c => c.c);

const rsi15m = calcRSI(closes15m, 14);
const rsi1h = calcRSI(closes1h, 14);
const rsi4h = calcRSI(closes4h, 14);

// EMA(50) и EMA(200) для 4H
const ema50_4h = calcEMA(closes4h, 50);
const ema200_4h = calcEMA(closes4h, 200);

// MACD для 15M
const macd15m = calcMACD(closes15m);

// ATR(14) для 15M
const atr15m = calcATR(candles15m, 14);

// === SCORE-BASED LOGIC ===
let bullScore = 0;
let bearScore = 0;
let reasons = [];

// 4H тренд: цена выше EMA200 → бычий (+3)
if (price > ema200_4h) {
  bullScore += 3;
  reasons.push('4H: Цена > EMA200 (бычий тренд)');
} else {
  bearScore += 3;
  reasons.push('4H: Цена < EMA200 (медвежий тренд)');
}

// 4H: цена выше EMA50 → дополнительный бычий сигнал (+1)
if (price > ema50_4h) {
  bullScore += 1;
  reasons.push('4H: Цена > EMA50');
} else {
  bearScore += 1;
  reasons.push('4H: Цена < EMA50');
}

// 15M RSI перепроданность → BUY сигнал (+2)
if (rsi15m < 30) {
  bullScore += 2;
  reasons.push('15M: RSI < 30 (перепроданность)');
}

// 15M RSI перекупленность → SELL сигнал (+2)
if (rsi15m > 70) {
  bearScore += 2;
  reasons.push('15M: RSI > 70 (перекупленность)');
}

// 1H RSI > 65 → блокировка покупки
let buyBlocked = false;
if (rsi1h > 65) {
  buyBlocked = true;
  reasons.push('1H: RSI > 65 (BUY заблокирован)');
}

// MACD гистограмма положительная → бычий (+1)
if (macd15m.histogram > 0) {
  bullScore += 1;
  reasons.push('15M: MACD гистограмма > 0');
} else {
  bearScore += 1;
  reasons.push('15M: MACD гистограмма < 0');
}

// 4H RSI выше 60 → слабый бычий (+1)
if (rsi4h > 50 && rsi4h < 70) {
  bullScore += 1;
}
if (rsi4h < 40) {
  bearScore += 1;
}

// Определяем сигнал
let signal = 'HOLD';
let confidence = 0;
const maxScore = 8; // Максимально возможный балл

if (bullScore > bearScore && bullScore >= 4 && !buyBlocked) {
  signal = 'BUY';
  confidence = Math.min(Math.round((bullScore / maxScore) * 100), 95);
} else if (bearScore > bullScore && bearScore >= 4) {
  signal = 'SELL';
  confidence = Math.min(Math.round((bearScore / maxScore) * 100), 95);
} else {
  signal = 'HOLD';
  confidence = 0;
}

// Стоп-лосс и тейк-профит на основе ATR
const stopLoss = signal === 'BUY'
  ? parseFloat((price - atr15m * 2).toFixed(6))
  : parseFloat((price + atr15m * 2).toFixed(6));

const takeProfit = signal === 'BUY'
  ? parseFloat((price + atr15m * 4).toFixed(6))
  : parseFloat((price - atr15m * 4).toFixed(6));

return [{
  json: {
    symbol,
    signal,
    confidence,
    price,
    stopLoss,
    takeProfit,
    atr: parseFloat(atr15m.toFixed(6)),
    rsi15m: parseFloat(rsi15m.toFixed(2)),
    rsi1h: parseFloat(rsi1h.toFixed(2)),
    rsi4h: parseFloat(rsi4h.toFixed(2)),
    ema50_4h: parseFloat(ema50_4h.toFixed(6)),
    ema200_4h: parseFloat(ema200_4h.toFixed(6)),
    macdHistogram: parseFloat(macd15m.histogram.toFixed(6)),
    bullScore,
    bearScore,
    buyBlocked,
    reasons,
    timestamp: new Date().toISOString()
  }
}];

